package codegen

import (
	"fmt"
	"go/format"
	"strings"

	"github.com/tork-go/orm/gen/analyze"
)

// header opens every generated file. The exact spelling is the one the
// Go toolchain and editors recognize as machine written, and the CLI's
// stale file cleanup trusts it before deleting anything.
const header = "// Code generated by tork. DO NOT EDIT.\n\n"

// Options configures one generation run.
type Options struct {
	// Package is the name of the generated package.
	Package string
}

// File is one generated file: a base name and formatted Go source.
// Codegen never touches the filesystem, so the name carries no
// directory.
type File struct {
	Name    string
	Content []byte
}

// Generate renders the whole schema. The input must be error free (the
// caller checks diag.HasErrors first); the only errors returned here
// are misuse of Options or an internal printer bug caught by gofmt.
func Generate(s *analyze.Schema, opts Options) ([]File, error) {
	if !isGoIdent(opts.Package) || isGoKeyword(opts.Package) {
		return nil, fmt.Errorf("codegen: package name %q is not a valid Go identifier", opts.Package)
	}
	g := &generator{schema: s, pkg: opts.Package, weakened: weakenedEdges(s)}

	var files []File
	seen := map[string]*analyze.Model{}
	for _, m := range s.Models {
		name := analyze.SnakeCase(m.Name) + ".gen.go"
		if prev, ok := seen[name]; ok {
			return nil, fmt.Errorf("codegen: models %q and %q both generate the file %q; rename one", prev.Name, m.Name, name)
		}
		seen[name] = m
		files = append(files, File{Name: name, Content: g.modelFile(m)})
	}
	if len(s.Enums) > 0 {
		files = append(files, File{Name: "enums.gen.go", Content: g.enumsFile()})
	}
	files = append(files, File{Name: "registry.gen.go", Content: g.registryFile()})

	// Formatting doubles as the parse check on everything emitted.
	// The only inputs codegen cannot fully validate on its own are the
	// Go identifiers a schema supplies through @go.type and
	// @default(go(...)), which may name anything at all, so the
	// message points there rather than blaming the printer.
	for i := range files {
		formatted, err := format.Source(files[i].Content)
		if err != nil {
			return nil, fmt.Errorf("codegen: generated %s does not parse: %w; check the Go names the schema supplies through @go.type and @default(go(...))", files[i].Name, err)
		}
		files[i].Content = formatted
	}
	return files, nil
}

// goKeywords are the words a generated identifier must never be. The
// analyzer accepts them in @go.type and go(...) because they are
// spelled like identifiers; the parse check above is what catches them
// in the end, and this list keeps the package name from getting there.
var goKeywords = map[string]bool{
	"break": true, "case": true, "chan": true, "const": true, "continue": true,
	"default": true, "defer": true, "else": true, "fallthrough": true, "for": true,
	"func": true, "go": true, "goto": true, "if": true, "import": true,
	"interface": true, "map": true, "package": true, "range": true, "return": true,
	"select": true, "struct": true, "switch": true, "type": true, "var": true,
}

func isGoKeyword(name string) bool { return goKeywords[name] }

// generator carries one run's fixed inputs. weakened marks the belongs
// to fields whose column level reference must drop to ReferencesTable
// because the typed form would tie package initialization into a cycle.
type generator struct {
	schema   *analyze.Schema
	pkg      string
	weakened map[*analyze.Field]bool
}

// weakenedEdges finds the foreign keys that cannot reference another
// model's package variable. Go orders package variable initialization
// by dependency, so any acyclic reference graph just works; only edges
// inside a cycle need help. Of the edges a cycle contains, the ones
// running from the alphabetically smaller model to the larger drop to
// ReferencesTable, which leaves only "downhill" typed edges and those
// can never form a cycle. Self references never enter the graph: they
// hoist a local inside their own builder instead.
//
// Only inline column references count. Composite and named foreign
// keys render inside a ForeignKeys method, and method bodies play no
// part in initialization order.
func weakenedEdges(s *analyze.Schema) map[*analyze.Field]bool {
	type edge struct {
		field    *analyze.Field
		from, to *analyze.Model
	}
	var edges []edge
	adjacent := map[*analyze.Model][]*analyze.Model{}
	for _, m := range s.Models {
		for _, f := range m.Fields {
			r := f.Relation
			if r == nil || r.Kind != analyze.RelBelongsTo || r.Target == m {
				continue
			}
			if len(r.Fields) != 1 || r.FKName != "" {
				continue
			}
			edges = append(edges, edge{f, m, r.Target})
			adjacent[m] = append(adjacent[m], r.Target)
		}
	}
	reaches := func(from, to *analyze.Model) bool {
		seen := map[*analyze.Model]bool{}
		stack := []*analyze.Model{from}
		for len(stack) > 0 {
			cur := stack[len(stack)-1]
			stack = stack[:len(stack)-1]
			if cur == to {
				return true
			}
			if seen[cur] {
				continue
			}
			seen[cur] = true
			stack = append(stack, adjacent[cur]...)
		}
		return false
	}
	weak := map[*analyze.Field]bool{}
	for _, e := range edges {
		if e.from.Name < e.to.Name && reaches(e.to, e.from) {
			weak[e.field] = true
		}
	}
	return weak
}

// docComment renders a doc comment: the schema's own words when it has
// them, the fallback otherwise. Multi line docs stay multi line.
func docComment(doc, fallback string) string {
	text := doc
	if text == "" {
		text = fallback
	}
	var b strings.Builder
	for _, line := range strings.Split(text, "\n") {
		b.WriteString("// " + line + "\n")
	}
	return b.String()
}

// enumsFile renders every enum's values as untyped string constants.
// Untyped on purpose: row struct fields must be exactly string for the
// ORM's field resolution, and an untyped constant assigns to one
// without a conversion in sight.
func (g *generator) enumsFile() []byte {
	var b strings.Builder
	b.WriteString(header)
	b.WriteString("package " + g.pkg + "\n\n")
	for i, e := range g.schema.Enums {
		if i > 0 {
			b.WriteString("\n")
		}
		fallback := fmt.Sprintf("%s values, stored in the %s database enum type.", e.Name, e.DBName)
		b.WriteString(docComment(e.Doc, fallback))
		b.WriteString("const (\n")
		for _, v := range e.Values {
			fmt.Fprintf(&b, "\t%s%s = %q\n", e.Name, analyze.GoName(v), v)
		}
		b.WriteString(")\n")
	}
	return []byte(b.String())
}

// registryFile renders AllModels, the one line migrations need.
func (g *generator) registryFile() []byte {
	var b strings.Builder
	b.WriteString(header)
	b.WriteString("package " + g.pkg + "\n\n")
	if len(g.schema.Models) == 0 {
		b.WriteString("import \"github.com/tork-go/orm\"\n\n")
		b.WriteString("// AllModels lists every generated model; this schema has none yet.\n")
		b.WriteString("func AllModels() []orm.Model {\n\treturn nil\n}\n")
		return []byte(b.String())
	}
	b.WriteString("import \"github.com/tork-go/orm\"\n\n")
	b.WriteString("// AllModels lists every generated model in name order, ready to\n")
	b.WriteString("// hand straight to migrations:\n//\n")
	fmt.Fprintf(&b, "//\tcli.Run(dsn, \"migrations\", %s.AllModels()...)\n", g.pkg)
	b.WriteString("func AllModels() []orm.Model {\n")
	b.WriteString("\treturn []orm.Model{\n")
	for _, m := range g.schema.Models {
		b.WriteString("\t\t" + varName(m) + ",\n")
	}
	b.WriteString("\t}\n}\n")
	return []byte(b.String())
}
